<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Characters\Templates\CharacterTemplateReadService;use App\Domain\Characters\Templates\CharacterTemplateService;use App\Domain\Media\CharacterVisuals\CharacterVisualAssetException;use App\Domain\WorldCatalog\CatalogStatus;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\CharacterTemplateRequest;use App\Models\CharacterTemplate;use Illuminate\Http\Request;use InvalidArgumentException;
final class CharacterTemplateController extends Controller{public function index(Request $r,CharacterTemplateReadService $read){$filters=$r->only(['status','body_type','character_class_id']);return view('admin.content.character-templates.index',['templates'=>$read->adminList($filters),'filters'=>$filters,'options'=>$read->options()]);}public function create(CharacterTemplateReadService $read){return$this->form(new CharacterTemplate(),$read);}public function store(CharacterTemplateRequest $r,CharacterTemplateService $service){return$this->save($r,$service,null);}public function show(CharacterTemplate $character_template,CharacterTemplateReadService $read){return view('admin.content.character-templates.show',['row'=>$read->detail($character_template)]);}public function edit(CharacterTemplate $character_template,CharacterTemplateReadService $read){return$this->form($character_template,$read);}public function update(CharacterTemplateRequest $r,CharacterTemplate $character_template,CharacterTemplateService $service){return$this->save($r,$service,$character_template);}public function destroy(CharacterTemplate $character_template,CharacterTemplateService $service){$service->setStatus($character_template,CatalogStatus::INACTIVE);return back()->with('status','Plantilla inactivada correctamente.');}public function activate(CharacterTemplate $character_template,CharacterTemplateService $service){return$this->status(function()use($service,$character_template){$service->setStatus($character_template,CatalogStatus::ACTIVE);},'Plantilla activada correctamente.');}public function deactivate(CharacterTemplate $character_template,CharacterTemplateService $service){return$this->status(function()use($service,$character_template){$service->setStatus($character_template,CatalogStatus::INACTIVE);},'Plantilla inactivada correctamente.');}public function hide(CharacterTemplate $character_template,CharacterTemplateService $service){return$this->status(function()use($service,$character_template){$service->setStatus($character_template,CatalogStatus::HIDDEN);},'Plantilla ocultada correctamente.');}public function destroyImage(CharacterTemplate $character_template,CharacterTemplateService $service){return$this->status(function()use($service,$character_template){$service->deleteImage($character_template);},'Imagen base eliminada correctamente.');}private function form($template,$read){$row=$template->exists?$read->detail($template):['model'=>$template,'visual'=>app(\App\Domain\Media\CharacterVisuals\CharacterVisualAssetService::class)->presentation()];return view('admin.content.character-templates.form',['row'=>$row,'options'=>$read->options()]);}private function save($r,$service,$template){try{$saved=$service->save($r->validated(),$template,$r->file('image'));return redirect()->route('admin.content.character-templates.show',$saved)->with('status',$template?'Plantilla actualizada correctamente.':'Plantilla creada correctamente.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}catch(CharacterVisualAssetException $e){return back()->withInput()->withErrors(['image'=>$e->getMessage()]);}}private function status($callback,$message){try{$callback();return back()->with('status',$message);}catch(\Throwable $e){return back()->withErrors(['content'=>$e->getMessage()]);}}}
